import { useState } from 'react';
import { ArrowLeft, ArrowUpRight } from 'lucide-react';
import { Button } from '@/layers/shared/ui';

interface TunnelSetupProps {
  onBack: () => void;
  onSaveToken: (token: string) => Promise<void>;
  tokenConfigured: boolean;
}

/** Token input form with back navigation and format validation. */
export function TunnelSetup({ onBack, onSaveToken, tokenConfigured }: TunnelSetupProps) {
  const [authToken, setAuthToken] = useState('');
  const [tokenError, setTokenError] = useState<string | null>(null);
  const [saving, setSaving] = useState(false);

  const handleSave = async () => {
    setSaving(true);
    setTokenError(null);
    try {
      await onSaveToken(authToken);
      setAuthToken('');
    } catch {
      setTokenError('Could not save token. Try again.');
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="space-y-3">
      <button
        onClick={onBack}
        className="text-muted-foreground hover:text-foreground -ml-1 inline-flex items-center gap-1 text-xs transition-colors"
      >
        <ArrowLeft className="size-3.5" />
        Back
      </button>

      <div className="space-y-2">
        <span className="text-muted-foreground text-xs font-medium tracking-wider uppercase">
          Auth Token
        </span>
        <div className="flex gap-2">
          <input
            type="password"
            placeholder="Paste token here"
            value={authToken}
            onChange={(e) => setAuthToken(e.target.value)}
            className="border-input bg-background placeholder:text-muted-foreground focus-visible:ring-ring flex-1 rounded-md border px-3 py-1.5 text-sm shadow-sm outline-none focus-visible:ring-1"
          />
          <Button
            onClick={handleSave}
            disabled={!authToken.trim() || saving}
            size="sm"
          >
            Save
          </Button>
        </div>
        {tokenError && <p className="text-destructive text-xs">{tokenError}</p>}
        {!tokenConfigured && (
          <p className="text-muted-foreground text-xs">
            Need a token?{' '}
            <a
              href="https://dashboard.ngrok.com/signup"
              target="_blank"
              rel="noopener noreferrer"
              className="text-foreground inline-flex items-center gap-0.5 underline underline-offset-2"
            >
              Sign up at ngrok.com
              <ArrowUpRight className="size-3" />
            </a>
          </p>
        )}
      </div>
    </div>
  );
}
```

